import React, { Component } from 'react';
import './Product.scss';
import Rskrf from '../../services/rskrf';
import { Helmet } from "react-helmet";


class Product extends Component {
    rskrf = new Rskrf();

    state = {
        name: '',
        raiting: '',
        raitingDetails: [],
        research_results: '',
        advantages: [],
        disadvantages: [],
        trademark: '',
        src: '',
    }

    componentWillMount = () => {
        this.rskrf.product(140852)
            .then((response) => {
                this.setState(() => {
                    return {
                        name: response.name,
                        raiting: response.points,
                        raitingDetails: response.indicators,
                        research_results: response.research_results,
                        advantages: response.indicators,
                        disadvantages: response["-"],
                        trademark: response.trademark,
                        src: response.image.src,
                    }
                });

                (function (w) {
                    function start() {
                        w.removeEventListener("YaMarketAffiliateLoad", start);
                        w.YaMarketAffiliate.createWidget({
                            containerId: "marketWidget",
                            type: "offers",
                            params: {
                                clid: 2310490,
                                searchText: response.name,
                                sovetnikPromo: false,
                                themeId: 4
                            }
                        });
                    }
                    w.YaMarketAffiliate
                        ? start()
                        : w.addEventListener("YaMarketAffiliateLoad", start);
                })(window);
            });
    }

    render() {
        const { name, raiting, trademark, advantages, disadvantages, research_results, src } = this.state;
        const plus = advantages.map((plus, index) => {
            return (
                <div className='raiting__block' key={index}>
                    <div className='raiting__text' >{plus.name}</div>
                    <div className='raiting__val'>{plus.value}</div>
                </div>
            )
        })


        return <>
            <div className='product'>
                <div className='product__top-block'>
                    <div className='product-image'>
                        <img className='product-image-img' src={`https://rskrf.ru/${src}`} alt="" />
                    </div>

                    <div className='product-info'>
                        <div className='product-info__block'>
                            <div className='product__trademark'>ТМ: {trademark}</div>
                            <h1 className='product__name' id='goodsName'>{name}</h1>
                            <div className='product__points'>Общий рейтинг {raiting}</div>
                            <div className='product__advantages'>
                                {plus}
                            </div>
                        </div>

                        <div className='product__controls'>
                            <button className='btn btn_black'>Добавить в избранное</button>
                        </div>

                        <Helmet>
                            <script src="https://aflt.market.yandex.ru/widget/script/api" type="text/javascript"></script>
                        </Helmet>
                        <div id="marketWidget"></div>
                    </div>
                </div>

                <div className='product-description'>
                    <div className='product-description__block'>
                        <span className='product-description__title'>Описание</span>
                    </div>
                    <p className='product-description__text'>{research_results}</p>
                    <span className='product-description__topic'>Недостатки:</span>

                    <div className='product-disadvantages'>
                        <ul className='product-disadvantages__list'>
                            {disadvantages.map((minus, index) => <li className='product-disadvantages__item' key={index}> {minus} </li>)}
                        </ul>
                    </div>
                </div>

            </div>
        </>;
    }
}

export default Product;