export default class Rskrf {

    _apiBase = 'https://rskrf.ru/api/';

    product = async (id) => {
        const api_call = await fetch(`${this._apiBase}product/${id}`);
        const response = await api_call.json();
        console.log(response);
        return response;
    }

    getCategories = async () => {
        const api_call = await fetch(`${this._apiBase}getcategories`);
        const response = await api_call.json();
        console.log(response);
        return response;
    }

    getResearches = async () => {
        const api_call = await fetch(`${this._apiBase}getresearches`);
        const response = await api_call.json();
        /* console.log(response); */
        return response;
    }

    getResearch = async () => {
        const api_call = await fetch(`${this._apiBase}research/13601`);
        const response = await api_call.json();
        console.log(response);
        return response;
    }

}